// ── NAV SCROLL ───────────────────────────────────────────────
  function navTo(id) {
    const el = document.getElementById(id);
    if (el) {
      el.scrollIntoView({ behavior: 'smooth', block: 'start' });
      // Update active state
      document.querySelectorAll('.nav-links a').forEach(a => {
        a.classList.toggle('active', a.getAttribute('onclick') && a.getAttribute('onclick').includes(id));
      });
      // Close mobile menu if open
      document.querySelector('.nav-links').classList.remove('open');
      document.getElementById('hamburger').classList.remove('active');
    }
  }

  // ── THEME TOGGLE ─────────────────────────────────────────────
  function toggleTheme() {
    const current = document.documentElement.getAttribute('data-theme') || 'dark';
    const next = current === 'dark' ? 'light' : 'dark';
    applyTheme(next);
  }

  function applyTheme(theme) {
    document.documentElement.setAttribute('data-theme', theme);
    const moon = document.getElementById('icon-moon');
    const sun  = document.getElementById('icon-sun');
    if (moon && sun) {
      moon.style.display = theme === 'dark'  ? 'block' : 'none';
      sun.style.display  = theme === 'light' ? 'block' : 'none';
    }
    localStorage.setItem('portfolio-theme', theme);
  }

  // Load saved theme
  const savedTheme = localStorage.getItem('portfolio-theme') || 'dark';
  applyTheme(savedTheme);

  // ── 2. ACTIVE NAV ON SCROLL ───────────────────────────────────
  const sections = document.querySelectorAll('section[id], div[id="contact"], div[id="home"]');
  const navLinks = document.querySelectorAll('.nav-links a');

  const observer = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        const id = entry.target.id;
        navLinks.forEach(a => {
          const oc = a.getAttribute('onclick') || '';
          a.classList.toggle('active', oc.includes("'" + id + "'"));
        });
      }
    });
  }, { rootMargin: '-40% 0px -55% 0px' });

  sections.forEach(s => observer.observe(s));

  // ── 3. SCROLL REVEAL ──────────────────────────────────────────
  const revealTargets = [
    '.skill-cell',
    '.project-card',
    '.exp-card',
    '.edu-item',
    '.cert-card',
    '.section-eyebrow',
    '.section-title'
  ].join(',');

  // Add reveal with IntersectionObserver — fallback: make visible after 800ms
  document.querySelectorAll(revealTargets).forEach((el, i) => {
    el.classList.add('reveal');
    el.style.transitionDelay = (i % 5) * 0.07 + 's';
  });

  const revealObs = new IntersectionObserver((entries) => {
    entries.forEach(e => {
      if (e.isIntersecting) {
        e.target.classList.add('visible');
        revealObs.unobserve(e.target);
      }
    });
  }, { threshold: 0.05, rootMargin: '0px 0px -30px 0px' });

  document.querySelectorAll('.reveal').forEach(el => revealObs.observe(el));

  // Fallback: if elements still hidden after 1s, force show all
  setTimeout(() => {
    document.querySelectorAll('.reveal:not(.visible)').forEach(el => {
      el.classList.add('visible');
    });
  }, 800);


